func TestProbeSourceURLUsesBrowserUserAgentAndFinalURL(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if got := r.Header.Get("User-Agent"); got != sourceProbeUserAgent {
			t.Fatalf("unexpected user agent %q", got)
		}
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte("<html><title>OK</title></html>"))
	}))
	defer srv.Close()

	row := probeSourceURL(t.Context(), &http.Client{Timeout: time.Second}, sourceProbeCandidate{
		Label: "local",
		Group: "test",
		URL:   srv.URL,
	})
	if row.Status != "readable" {
		t.Fatalf("expected readable probe, got %#v", row)
	}
	if row.HTTPStatus != http.StatusOK {
		t.Fatalf("expected HTTP 200, got %#v", row)
	}
	if row.FinalURL != srv.URL {
		t.Fatalf("expected final URL %q, got %q", srv.URL, row.FinalURL)
	}
}

func TestProbeSourceURLReportsLargerBodyCapAndTruncation(t *testing.T) {
	body := strings.Repeat(" ", 70*1024) + `<html><title>Just a moment...</title><script src="https://challenges.cloudflare.com"></script></html>` + strings.Repeat(" ", sourceProbeReadLimitByte)
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte(body))
	}))
	defer srv.Close()

	row := probeSourceURL(t.Context(), &http.Client{Timeout: time.Second}, sourceProbeCandidate{
		Label: "local",
		Group: "test",
		URL:   srv.URL,
	})
	if row.Status != "readable" {
		t.Fatalf("expected synthetically padded response to remain readable, got %#v", row)
	}
	if !row.Truncated {
		t.Fatalf("expected oversized probe body to report truncation, got %#v", row)
	}
	if row.BodyBytes != sourceProbeReadLimitByte {
		t.Fatalf("expected capped body bytes %d, got %#v", sourceProbeReadLimitByte, row)
	}
}

